function outer() {
  let x = 10; // function scope
  if (true) {
    let y = 20; // block scope
  }
  // y is not accessible here
}

def outer():
    x = 10  # function scope
    if True:
        y = 20  # block scope in other languages, but not Python
    print(y)  # accessible in Python
outer()

public static void outer() {
    int x = 10; // function scope
    if (true) {
        int y = 20; // block scope
    }
    // y is not accessible here
}

CREATE PROCEDURE test AS
DECLARE @x INT = 10;
IF 1 = 1
    DECLARE @y INT = 20;
-- scope ends
END;
